     7→export class ProcessUserPromotion {
     8→  constructor(
     9→    private getUser: GetUserNRC,
    10→    private getAccessPoint: GetAccessPoint,
    11→    private postPromotion: PostPromotion,
    12→    private sqsDLQService: SqsService,
    13→    private sqsEmailService: SqsService,
    14→    private sqsService: SqsService
    15→  ) {}
    16→
    17→  async execute(event: any): Promise<PostPromotionResponse> {
    18→    try {
    19→      const body = JSON.parse(event.body);
    20→      const userNRC = await this.getUser.execute(
    21→        COMPANY_IDENTIFICATION,
    22→        body.identification
    23→      );
    24→
    25→      const productIdentification = await this.getAccessPoint.execute(
    26→        COMPANY_IDENTIFICATION,
    27→        userNRC
    28→      );
    29→
    30→      const postPromotion = await this.postPromotion.execute(
    31→        userNRC,
    32→        productIdentification.identification,
    33→        COMPANY_IDENTIFICATION
    34→      );
    35→
    36→      return postPromotion;
    37→    } catch (error: any) {
    38→      const classifiedError = classifyError(error);
    39→      const body = JSON.parse(event.body);
    40→
    41→      body.error = classifiedError.message;
    42→      body.errorType = classifiedError.type;
    43→
    44→      const message = {
    45→        source: "NTS-App-Fintech-FeeExemption",
    46→        messageId: event.messageId,
    47→        body: body,
    48→      };
    49→
